module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output wfull,
    output rempty,
    output [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

reg [ADDR_WIDTH:0] wptr, rptr;
wire [ADDR_WIDTH-1:0] waddr, raddr;
wire wenc, renc;
reg [WIDTH-1:0] ram [DEPTH-1:0];

// Dual-port RAM
assign waddr = wptr[ADDR_WIDTH-1:0];
assign raddr = rptr[ADDR_WIDTH-1:0];
assign wenc = wptr[ADDR_WIDTH] ^ wptr[ADDR_WIDTH-1];
assign renc = rptr[ADDR_WIDTH] ^ rptr[ADDR_WIDTH-1];

always @(posedge wclk or negedge wrstn) begin
    if (~wrstn) begin
        wptr <= 0;
    end else if (winc & ~wfull) begin
        ram[waddr] <= wdata;
        wptr <= wptr + 1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (~rrstn) begin
        rptr <= 0;
    end else if (rinc & ~rempty) begin
        rptr <= rptr + 1;
    end
end

// Read pointer synchronizer
reg [ADDR_WIDTH:0] rptr_sync;
always @(posedge wclk or negedge wrstn) begin
    if (~wrstn) begin
        rptr_sync <= 0;
    end else begin
        rptr_sync <= rptr;
    end
end

// Write pointer synchronizer
reg [ADDR_WIDTH:0] wptr_sync;
always @(posedge rclk or negedge rrstn) begin
    if (~rrstn) begin
        wptr_sync <= 0;
    end else begin
        wptr_sync <= wptr;
    end
end

// Empty and full signals
assign rempty = (rptr == rptr_sync);
assign wfull = (wptr[ADDR_WIDTH-1:0] == rptr_sync[ADDR_WIDTH-1:0]) & (wptr[ADDR_WIDTH] ^ rptr_sync[ADDR_WIDTH]);

assign rdata = ram[raddr];

endmodule
